import{_ as e,c as a,o as t,ae as i}from"./chunks/framework.BHrE6nLq.js";const s="/images/wireshark/wireshark_gerald.png",p=JSON.parse('{"title":"wireshark 简介","description":"","frontmatter":{},"headers":[],"relativePath":"network/wireshark/wireshark_introduction.md","filePath":"network/wireshark/wireshark_introduction.md"}'),h={name:"network/wireshark/wireshark_introduction.md"};function o(n,r,l,k,_,w){return t(),a("div",null,r[0]||(r[0]=[i('<h1 id="wireshark-简介" tabindex="-1">wireshark 简介 <a class="header-anchor" href="#wireshark-简介" aria-label="Permalink to &quot;wireshark 简介&quot;">​</a></h1><p>​ Wireshark 的历史相当久远丰富，其最初的版本叫作Ethereal，由毕业于密苏里大学堪萨斯城分校计算机科学专业的Gerald Combs 出于项目需要而开发，并于1998 年以GNU Public Licence(GPL)开源许可证发布。</p><p>​ 在Ethereal 发布八年之后，Combs 辞职并另谋高就，但是在那个时候他的雇主公司掌握着Ethereal 的商标权，而Combs 也没能和其雇主就取得Ethereal商标达成协议。于是Combs 和整个开发团队在2006 年年中的时候将这个项目重新冠名为Wireshark。</p><p>​ Wireshark 随后迅速地取得了大众的青睐，而其合作开发团队也壮大到500人以上，然而Ethereal 项目却再没有前进过一步。</p><p><img src="'+s+'" alt="wireshark_gerald"></p><ul><li>官网：<a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">https://www.wireshark.org/</a></li><li>github：<a href="https://github.com/wireshark/wireshark" target="_blank" rel="noreferrer">https://github.com/wireshark/wireshark</a></li></ul>',6)]))}const d=e(h,[["render",o]]);export{p as __pageData,d as default};
